  static List<CompletedSet> buildHistory() {
    final d = jsonDecode(_data) as Map<String, dynamic>;
    final ex = (d['ex'] as List).cast<String>();
    final result = <CompletedSet>[];
    for (final session in (d['s'] as List)) {
      final s = session as List;
      final date = DateTime.parse(s[1] as String);
      for (final e in (s[4] as List)) {
        final entry = e as List;
        result.add(CompletedSet(
          exerciseName: ex[entry[0] as int],
          weight: (entry[1] as num).toDouble(),
          reps: entry[2] as int,
          date: date,
          isWarmup: (entry[3] as int) == 1,
        ));
      }
    }
    return result;
  }

