    for (final session in (d['s'] as List)) {
      final s = session as List;
      final name = s[0] as String;
      final date = DateTime.parse(s[1] as String);
      final duration = s[2] as int?;
      final xp = s[3] as int;
      final sets = <CompletedSet>[];
      for (final e in (s[4] as List)) {
        final entry = e as List;
        sets.add(CompletedSet(
          exerciseName: ex[entry[0] as int],
          weight: (entry[1] as num).toDouble(),
          reps: entry[2] as int,
          date: date,
          isWarmup: (entry[3] as int) == 1,
        ));
      }
      result.add(WorkoutLog(
        sessionName: name,
        date: date,
        sets: sets,
        xpEarned: xp,
        durationMinutes: duration,
      ));
    }
    return result;
  }
}
